patch:
--- a/decoder.sv
+++ b/decoder.sv
@@ -8,9 +8,10 @@ module decoder_wrapper (
 );
   decoder_3to8 dec_inst (
     .sel(address),
+    .enable(enable_in),
     .out_0(output_line)
   );
 endmodule

before_code:
module decoder_3to8 (
  input [2:0] sel,
  input enable,
  output [7:0] out_0
);
  assign out_0 = enable ? (8'b1 << sel) : 8'b0;
endmodule

module decoder_wrapper (
  input [2:0] address,
  input enable_in,
  output [7:0] output_line
);
  decoder_3to8 dec_inst (
    .sel(address),
    .out_0(output_line)
  );
endmodule

after_code:
module decoder_3to8 (
  input [2:0] sel,
  input enable,
  output [7:0] out_0
);
  assign out_0 = enable ? (8'b1 << sel) : 8'b0;
endmodule

module decoder_wrapper (
  input [2:0] address,
  input enable_in,
  output [7:0] output_line
);
  decoder_3to8 dec_inst (
    .sel(address),
    .enable(enable_in),
    .out_0(output_line)
  );
endmodule
